import '../lib/asset.dart';
import '../lib/asset_cache.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final cache = AssetCache(2);
  cache.put('a', Asset('1', <int>[1]));
  cache.put('b', Asset('1', <int>[2]));
  check(cache.get('a')?.revision == '1', 'initial read');
  cache.put('a', Asset('2', <int>[9]));
  cache.put('c', Asset('1', <int>[3]));
  check(cache.get('b') == null, 'replacement and read make a recent key');
  check(cache.get('a')?.revision == '2', 'replacement value retained');
  cache.put('d', Asset('1', <int>[4]));
  check(cache.get('c') == null && cache.get('a') != null && cache.get('d') != null, 'composed access order');
  print('final tests passed');
}
